mapper.select:
SELECT IFNULL(AVG(review_star), 0)
FROM review
WHERE bidder_idx = #{memIdx}

SELECT b.bidder_idx
FROM bid b
WHERE b.bid_idx = #{bidIdx}

SELECT r.review_title AS reviewTitle, r.review_content AS reviewContent, r.review_star AS reviewStar, r.review_regdate AS reviewRegdate, a.auction_title AS auctionTitle,
a.auction_target_price AS auctionTargetPrice, m.mem_name AS memName, bidder.mem_name AS bidderName, b.bid_regdate AS bidRegdate
FROM review r JOIN bid b ON r.bid_idx = b.bid_idx JOIN auction a ON r.auction_idx = a.auction_idx JOIN member m ON r.buyer_idx = m.mem_idx JOIN member bidder ON b.bidder_idx = bidder.mem_idx WHERE r.review_idx = #{reviewIdx}

mapper.update:
UPDATE review
SET review_is_deleted = 'N'
WHERE review_idx = #{reviewIdx}
